          </Button>
        )}

        {onReanalyze && (
          <Button
            variant="outline"
            className="w-full"
            onClick={(e) => {
              e.preventDefault();
              onReanalyze(race.id);
            }}
            disabled={reanalyzeDisabled}
            data-testid={`button-reanalyze-${race.id}`}
          >
            <RefreshCw className={`h-4 w-4 mr-2 ${reanalyzeDisabled ? 'animate-spin' : ''}`} />
