@layer base {
  * {
    @apply border-border;
  }

  body {
    @apply font-sans antialiased bg-background text-foreground;
  }
}

/**
 * Using the elevate system.
 * Automatic contrast adjustment.
 *
 * <element className="hover-elevate" />
 * <element className="active-elevate-2" />
 *
 * // Using the tailwind utility when a data attribute is "on"
 * <element className="toggle-elevate data-[state=on]:toggle-elevated" />
 * // Or manually controlling the toggle state
 * <element className="toggle-elevate toggle-elevated" />
 *
 * Elevation systems have to handle many states.
 * - not-hovered, vs. hovered vs. active  (three mutually exclusive states)
 * - toggled or not
 * - focused or not (this is not handled with these utilities)
 *
 * Even without handling focused or not, this is six possible combinations that
 * need to be distinguished from eachother visually.
 */
@layer utilities {

  /* Hide ugly search cancel button in Chrome until we can style it properly */
  input[type="search"]::-webkit-search-cancel-button {
    @apply hidden;
  }

  /* Placeholder styling for contentEditable div */
  [contenteditable][data-placeholder]:empty::before {
    content: attr(data-placeholder);
    color: hsl(var(--muted-foreground));
    pointer-events: none;
  }

  /* .no-default-hover-elevate/no-default-active-elevate is an escape hatch so consumers of
   * buttons/badges can remove the automatic brightness adjustment on interactions
   * and program their own. */
  .no-default-hover-elevate {}

  .no-default-active-elevate {}


  /**
   * Toggleable backgrounds go behind the content. Hoverable/active goes on top.
   * This way they can stack/compound. Both will overlap the parent's borders!
   * So borders will be automatically adjusted both on toggle, and hover/active,
   * and they will be compounded.
   */
  .toggle-elevate::before,
  .toggle-elevate-2::before {
    content: "";
    pointer-events: none;
    position: absolute;
    inset: 0px;
    /*border-radius: inherit;   match rounded corners */
    border-radius: inherit;
    z-index: -1;
    /* sits behind content but above backdrop */
  }

  .toggle-elevate.toggle-elevated::before {
    background-color: var(--elevate-2);
  }

  /* If there's a 1px border, adjust the inset so that it covers that parent's border */
  .border.toggle-elevate::before {
    inset: -1px;
  }

  /* Does not work on elements with overflow:hidden! */
  .hover-elevate:not(.no-default-hover-elevate),
  .active-elevate:not(.no-default-active-elevate),
  .hover-elevate-2:not(.no-default-hover-elevate),
  .active-elevate-2:not(.no-default-active-elevate) {
    position: relative;
    z-index: 0;
  }

  .hover-elevate:not(.no-default-hover-elevate)::after,
  .active-elevate:not(.no-default-active-elevate)::after,
  .hover-elevate-2:not(.no-default-hover-elevate)::after,
  .active-elevate-2:not(.no-default-active-elevate)::after {
    content: "";
    pointer-events: none;
    position: absolute;
    inset: 0px;
    /*border-radius: inherit;   match rounded corners */
    border-radius: inherit;
    z-index: 999;
    /* sits in front of content */
  }

  .hover-elevate:hover:not(.no-default-hover-elevate)::after,
  .active-elevate:active:not(.no-default-active-elevate)::after {
    background-color: var(--elevate-1);
  }

  .hover-elevate-2:hover:not(.no-default-hover-elevate)::after,
  .active-elevate-2:active:not(.no-default-active-elevate)::after {
    background-color: var(--elevate-2);
  }

  /* If there's a 1px border, adjust the inset so that it covers that parent's border */
  .border.hover-elevate:not(.no-hover-interaction-elevate)::after,
  .border.active-elevate:not(.no-active-interaction-elevate)::after,
  .border.hover-elevate-2:not(.no-hover-interaction-elevate)::after,
  .border.active-elevate-2:not(.no-active-interaction-elevate)::after,
  .border.hover-elevate:not(.no-hover-interaction-elevate)::after {
    inset: -1px;
  }
}

client/src/pages/NYSenateCompare.tsx.content:
import { useState } from "react";
import { useQuery, useMutation } from "@tanstack/react-query";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { ComparisonPanel } from "@/components/ComparisonPanel";
import { Skeleton } from "@/components/ui/skeleton";
import { apiRequest } from "@/lib/queryClient";
import type { Candidate, ComparisonResult } from "@shared/schema";
import { ArrowLeft, Loader2 } from "lucide-react";
import { Link } from "wouter";

const NY_SENATE_CANDIDATES = [
  "Alexandria Ocasio-Cortez",
  "Letitia James",
  "Pat Ryan",
  "Ritchie Torres",
  "Tom Suozzi",
];

export default function NYSenateCompare() {
  const [candidate1Name, setCandidate1Name] = useState<string>("");
  const [candidate2Name, setCandidate2Name] = useState<string>("");
  const [comparisonResult, setComparisonResult] = useState<ComparisonResult | null>(null);

  const { data: candidates, isLoading: candidatesLoading } = useQuery<Candidate[]>({
    queryKey: ["/api/candidates/ny-senate"],
  });

  const compareMutation = useMutation({
    mutationFn: async () => {
      const c1 = candidates?.find((c) => c.name === candidate1Name);
      const c2 = candidates?.find((c) => c.name === candidate2Name);

      if (!c1 || !c2) throw new Error("Candidates not found");

      const result = await apiRequest<ComparisonResult>(
        "POST",
        "/api/compare",
        { candidate1Id: c1.id, candidate2Id: c2.id }
      );
      return result;
    },
    onSuccess: (data) => {
      setComparisonResult(data);
    },
  });

  const handleCompare = () => {
    if (candidate1Name && candidate2Name && candidate1Name !== candidate2Name) {
      compareMutation.mutate();
    }
  };

  const canCompare = candidate1Name && candidate2Name && candidate1Name !== candidate2Name;

  return (
    <div className="min-h-screen bg-background">
      <header className="border-b bg-card sticky top-0 z-10">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-4">
          <div className="flex items-center gap-4">
            <Link href="/">
              <Button variant="ghost" size="icon" data-testid="button-back">
                <ArrowLeft className="h-5 w-5" />
              </Button>
            </Link>
            <div>
              <h1 className="text-2xl font-bold">New York Senate Race</h1>
              <p className="text-sm text-muted-foreground">Schumer Replacement Scenarios</p>
            </div>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
        <Card className="mb-8">
          <CardHeader>
            <CardTitle>Compare Potential Candidates</CardTitle>
            <p className="text-sm text-muted-foreground mt-2">
              Analyze head-to-head matchups between potential candidates to replace Senator Schumer
            </p>
          </CardHeader>
          <CardContent>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-4 items-end">
              <div className="space-y-2">
                <label className="text-sm font-medium">Candidate 1</label>
                {candidatesLoading ? (
                  <Skeleton className="h-10 w-full" />
                ) : (
                  <Select value={candidate1Name} onValueChange={setCandidate1Name}>
                    <SelectTrigger data-testid="select-candidate1">
                      <SelectValue placeholder="Select first candidate" />
                    </SelectTrigger>
                    <SelectContent>
                      {NY_SENATE_CANDIDATES.map((name) => (
                        <SelectItem key={name} value={name}>
                          {name}
                        </SelectItem>
                      ))}
                    </SelectContent>
                  </Select>
                )}
              </div>

              <div className="space-y-2">
                <label className="text-sm font-medium">Candidate 2</label>
                {candidatesLoading ? (
                  <Skeleton className="h-10 w-full" />
                ) : (
                  <Select value={candidate2Name} onValueChange={setCandidate2Name}>
                    <SelectTrigger data-testid="select-candidate2">
                      <SelectValue placeholder="Select second candidate" />
                    </SelectTrigger>
                    <SelectContent>
                      {NY_SENATE_CANDIDATES.filter((n) => n !== candidate1Name).map((name) => (
                        <SelectItem key={name} value={name}>
                          {name}
                        </SelectItem>
                      ))}
                    </SelectContent>
                  </Select>
                )}
              </div>

              <Button
                onClick={handleCompare}
                disabled={!canCompare || compareMutation.isPending}
                className="w-full"
                data-testid="button-generate-comparison"
              >
                {compareMutation.isPending ? (
                  <>
                    <Loader2 className="mr-2 h-4 w-4 animate-spin" />
                    Analyzing...
                  </>
                ) : (
                  "Generate Comparison"
                )}
              </Button>
            </div>
          </CardContent>
        </Card>

        {compareMutation.isPending && (
          <div className="space-y-6">
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
              {[1, 2].map((i) => (
                <Card key={i}>
                  <CardHeader>
                    <Skeleton className="h-24 w-24 rounded-full mb-4" />
                    <Skeleton className="h-8 w-48" />
                  </CardHeader>
                  <CardContent>
                    <Skeleton className="h-4 w-full mb-2" />
                    <Skeleton className="h-3 w-32" />
                  </CardContent>
                </Card>
              ))}
            </div>
          </div>
        )}

        {comparisonResult && !compareMutation.isPending && (
          <ComparisonPanel comparison={comparisonResult} />
        )}

        {!comparisonResult && !compareMutation.isPending && (
          <Card className="p-12 text-center">
            <p className="text-muted-foreground">Select two candidates above to generate a comparison</p>
          </Card>
        )}
      </main>
    </div>
  );
}

